@push('scripts')<script>const field=document.getElementById('schema_json'),feedback=document.getElementById('json-feedback');const validateJson=()=>{try{JSON.parse(field.value);field.classList.remove('is-invalid');feedback.className='form-text text-success';feedback.textContent='Valid JSON.';return true}catch(error){field.classList.add('is-invalid');feedback.className='form-text text-danger';feedback.textContent='Invalid JSON: '+error.message;return false}};field?.addEventListener('input',validateJson);field?.closest('form')?.addEventListener('submit',event=>{if(!validateJson())event.preventDefault()});validateJson();</script>@endpush
